const body = $input.first().json.body || $input.first().json;
const own_profile_id = body.own_profile_id;
const user_id = body.user_id;
const own_username = typeof body.own_username === 'string' ? body.own_username : '';

if (!own_profile_id) throw new Error('Missing required field: own_profile_id');
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(own_profile_id)) {
  throw new Error('own_profile_id must be a valid UUID');
}
if (!user_id) throw new Error('Missing required field: user_id');
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(user_id)) {
  throw new Error('user_id must be a valid UUID');
}

// own_username is optional but heavily used downstream — the Build
// Claude Prompt node needs it to label the OWN ACCOUNT section and the
// Parse & Enrich node needs it to scrub Claude's example_posts of
// references to the user's own handle. If it's missing, the workflow
// still runs but loses example-scrubbing precision.
return [{ json: { own_profile_id, user_id, own_username } }];

// Merge own posts and competitor list, validate we have enough, build competitor IDs for next query
// Fetch Own Posts and Fetch Competitors are parallel branches from Validate Input — both will have executed by now.
let ownItems = [];
let compItems = [];
try { ownItems = $('Fetch Own Posts').all(); } catch (e) { ownItems = []; }
try { compItems = $('Fetch Competitors').all(); } catch (e) { compItems = []; }

// HTTP node may return either one item whose json is an array, or N items each a row.
function flatten(items) {
  if (!items || items.length === 0) return [];
  if (items.length === 1 && Array.isArray(items[0].json)) return items[0].json;
  return items.map(i => i.json);
}

const own_posts = flatten(ownItems);
const competitors = flatten(compItems);

const own_profile_id = $('Validate Input').first().json.own_profile_id;

if (own_posts.length === 0) {
  throw new Error(`No posts found for own_profile_id ${own_profile_id}. Scrape your own profile first.`);
}
if (competitors.length < 2) {
  throw new Error(`Need at least 2 competitor profiles. Found: ${competitors.length}. Add and scrape competitors first.`);
}

const competitor_ids = competitors.map(c => c.id);

return [{ json: { own_profile_id, own_posts, competitors, competitor_ids } }];

function sanitize(str) {
  if (!str) return '';
  return str.replace(/[\uD800-\uDFFF]/g, '').replace(/[\x00-\x1F\x7F]/g, ' ').trim();
}

function median(nums) {
  const s = nums.filter(n => Number.isFinite(n)).slice().sort((a, b) => a - b);
  if (s.length === 0) return 0;
  const mid = Math.floor(s.length / 2);
  return s.length % 2 ? s[mid] : (s[mid - 1] + s[mid]) / 2;
}

const upstream = $('Merge Profiles').first().json;
const validate = $('Validate Input').first().json;
const { own_profile_id, own_posts, competitors } = upstream;
const own_username = (validate.own_username || '').toLowerCase();

// n8n's HTTP node returns either ONE item whose json is the full array,
// OR N items each carrying one row, depending on response shape and node
// version. Merge Profiles uses this same flatten pattern — without it,
// `$input.first().json` is just the FIRST post (a single object), the
// scoring loop runs once, and Claude only ever sees one post. That's
// exactly the failure we kept hitting on coffee shop runs.
function flattenInput(items) {
  if (!items || items.length === 0) return [];
  if (items.length === 1 && Array.isArray(items[0].json)) return items[0].json;
  return items.map(i => i.json);
}
const allCompetitorPosts = flattenInput($input.all());
console.log('Build Claude Prompt: received ' + allCompetitorPosts.length + ' competitor posts');

// Group competitor posts by profile_id, compute creator-level medians.
const postsByProfile = {};
for (const post of allCompetitorPosts) {
  if (!postsByProfile[post.profile_id]) postsByProfile[post.profile_id] = [];
  postsByProfile[post.profile_id].push(post);
}
const competitorById = {};
for (const c of competitors) competitorById[c.id] = c;

// Score every competitor post:
//   score = outlier_ratio * log10(likes)
//   outlier_ratio = post.likes / creator_median (median, not mean — a
//   single viral hit shouldn't pull the baseline up and hide itself).
//   The log10 weights absolute popularity so a 5x outlier at 5000 likes
//   beats a 5x at 50 likes.
const scoredPosts = [];
for (const profileId of Object.keys(postsByProfile)) {
  const posts = postsByProfile[profileId];
  const med = Math.max(median(posts.map(p => p.likes || 0)), 1);
  const competitor = competitorById[profileId];
  const username = competitor ? competitor.username : 'unknown';
  for (const p of posts) {
    const likes = p.likes || 0;
    const outlier_ratio = likes / med;
    const score = outlier_ratio * Math.log10(Math.max(likes, 1));
    scoredPosts.push({
      caption: sanitize(p.caption || '').slice(0, 200),
      likes,
      comments: p.comments || 0,
      views: p.views || 0,
      content_type: p.content_type || 'unknown',
      posted_at: (p.posted_at || '').slice(0, 10),
      competitor: '@' + username,
      creator_median: Math.round(med),
      outlier_ratio: Math.round(outlier_ratio * 100) / 100,
      score: Math.round(score * 100) / 100,
    });
  }
}

// Top 50 across ALL competitors by score. Themes get extracted from
// these proven winners only — Claude no longer has to invent patterns
// and validate them post-hoc.
const topPosts = scoredPosts.sort((a, b) => b.score - a.score).slice(0, 50);

// User's own top 10 by likes — for context only, never a theme source.
const ownTop10 = own_posts
  .slice()
  .sort((a, b) => (b.likes || 0) - (a.likes || 0))
  .slice(0, 10)
  .map(p => ({
    caption: sanitize(p.caption || '').slice(0, 200),
    likes: p.likes || 0,
    content_type: p.content_type || 'unknown',
  }));

function formatTopPostLine(p, i) {
  return '  ' + String(i + 1).padStart(2) + '. ' + p.competitor +
    ' [' + p.content_type + '] ' + p.posted_at +
    ' | likes:' + p.likes + ' (' + p.outlier_ratio + 'x ' + p.competitor + ' median)' +
    ' comments:' + p.comments +
    ' | score:' + p.score +
    ' | "' + p.caption + '"';
}

function formatOwnPostLine(p, i) {
  return '  ' + String(i + 1).padStart(2) + '. [' + p.content_type + '] likes:' + p.likes + ' | "' + p.caption + '"';
}

const competitorCount = competitors.length;
const ownHandleLabel = own_username ? '@' + own_username : 'own_account';

const topPostsBlock = topPosts.length > 0
  ? topPosts.map(formatTopPostLine).join('\n')
  : '  (no competitor posts scraped yet)';
const ownPostsBlock = ownTop10.length > 0
  ? ownTop10.map(formatOwnPostLine).join('\n')
  : '  (no own posts scraped)';

const validHandlesList = competitors.map(c => '@' + c.username).join(', ');

const systemPrompt = 'You are a social media growth strategist. Group high-performing Instagram posts into actionable, filmable content themes. Every theme you propose must be specific enough that a creator could film it tomorrow without asking follow-up questions. Return ONLY a valid JSON array, no markdown fences, no commentary outside the JSON.';

const userPrompt = 'Here are the ' + topPosts.length + ' highest-performing Instagram posts across ' + competitorCount + ' competitor accounts.\n\n' +
  'Each post significantly outperformed its creator typical content. The outlier_ratio shows by how much it beat that creator median; the score combines outlier_ratio with absolute popularity.\n\n' +
  '--- COMPETITOR TOP POSTS (' + topPosts.length + ' posts, sorted by score descending) ---\n' +
  topPostsBlock + '\n\n' +
  '--- USER OWN TOP 10 POSTS (CONTEXT ONLY — never a theme source) ---\n' +
  'Account: ' + ownHandleLabel + '\n' +
  ownPostsBlock + '\n\n' +
  'YOUR TASK:\n' +
  '1. Group the ' + topPosts.length + ' competitor posts into 5-8 distinct ACTIONABLE themes.\n' +
  '2. Each theme must be defined by WHAT MAKES IT FILMABLE — specific format, visual style, hook technique, or content structure. NOT abstract category names.\n' +
  '   BAD theme: "Community engagement content"\n' +
  '   GOOD theme: "Behind-the-counter process reel with ASMR-style close-ups"\n' +
  '   BAD theme: "Lifestyle posts"\n' +
  '   GOOD theme: "Slow-motion product handover with locked-off camera and natural light"\n' +
  '3. For each theme, select up to 3 example posts that best represent it. Examples MUST come from the COMPETITOR list above. Copy outlier_ratio verbatim from the post line.\n' +
  '4. For each theme, check whether the user own posts (top 10 above) show this pattern. Set user_already_does accordingly.\n' +
  '5. For themes where user_already_does is true, include a level_up tip — one specific concrete thing competitors do differently to make this format land harder.\n\n' +
  'Return a JSON ARRAY (target 5-8 items, max 10). Each item MUST follow this exact shape:\n' +
  '{\n' +
  '  "theme_name": "specific filmable name (8-15 words ok, avoid abstract nouns)",\n' +
  '  "why_it_works": "1-2 sentences on the algorithmic/psychological reason this format pops",\n' +
  '  "avg_score": 12.5,\n' +
  '  "example_posts": [\n' +
  '    {"caption_preview": "first 80 chars of the original caption", "likes": 1234, "comments": 56, "competitor": "@username", "outlier_ratio": 4.2}\n' +
  '  ],\n' +
  '  "user_already_does": false,\n' +
  '  "level_up": "specific tip when user_already_does is true, otherwise null",\n' +
  '  "brief": {\n' +
  '    "content": "what to film, in one sentence — length, shot type, pacing",\n' +
  '    "hook": "the literal opening 3 seconds, word-for-word",\n' +
  '    "caption": "multi-line template using \\n",\n' +
  '    "posting_time": "specific day + 2-hour window",\n' +
  '    "hashtags": ["five", "to", "eight", "plain", "tags"]\n' +
  '  }\n' +
  '}\n\n' +
  'Rules:\n' +
  '- example_posts.competitor must be EXACTLY one of: ' + validHandlesList + '. NEVER ' + ownHandleLabel + ', "own_account", "user", or any other value. If you cannot find a real competitor post that fits, drop the theme.\n' +
  '- example_posts.outlier_ratio: copy verbatim from the source post in the COMPETITOR list (it is the number after "(" e.g. "(4.2x ...").\n' +
  '- avg_score: average of the source-post scores for the example posts you chose.\n' +
  '- Sort the array: user_already_does=false items first (new opportunities), then by avg_score descending within each group.\n' +
  '- All brief.* fields are REQUIRED strings except hashtags which is a REQUIRED array of 5-8 plain strings without # prefix.\n' +
  '- level_up REQUIRED when user_already_does is true, null otherwise.\n' +
  '- Return ONLY the JSON array. No markdown fences. No commentary before or after.';

return [{
  json: {
    own_profile_id,
    own_username,
    system_prompt: systemPrompt,
    user_prompt: userPrompt,
    competitor_count: competitorCount,
    top_posts_count: topPosts.length,
  },
}];

const resp = $input.first().json;
const rawText = resp?.content?.[0]?.text;
if (!rawText) throw new Error('Claude returned no content. Response: ' + JSON.stringify(resp));

if (resp?.stop_reason === 'max_tokens') {
  throw new Error('Claude hit max_tokens (' + rawText.length + ' chars generated). Bump max_tokens in the Call Claude API node — the JSON array was truncated mid-stream.');
}

// Robust array extractor — Claude sometimes wraps JSON in ```fences``` and
// adds prose around it. Pull the first valid array we can find.
function extractJsonArray(text) {
  if (!text) return '';
  const fence = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fence) return fence[1].trim();
  const trimmed = text.trim();
  if (trimmed.startsWith('[')) return trimmed;
  const start = trimmed.indexOf('[');
  const end = trimmed.lastIndexOf(']');
  if (start >= 0 && end > start) return trimmed.slice(start, end + 1);
  return trimmed;
}

const cleaned = extractJsonArray(rawText);

let themes;
try {
  themes = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + ' (cleaned_length=' + cleaned.length + ').\nStart: ' + cleaned.slice(0, 300) + '\nEnd: ' + cleaned.slice(-300));
}

if (!Array.isArray(themes)) throw new Error('Expected JSON array, got: ' + typeof themes);
console.log('Claude returned ' + themes.length + ' themes');

const upstream = $('Build Claude Prompt').first().json;
const own_profile_id = upstream.own_profile_id;
const own_username = (upstream.own_username || '').toLowerCase();
const total_competitors = upstream.competitor_count;

// Safety scrub: drop any example_posts that reference the user's own handle
// or generic placeholders. The prompt forbids these but Claude occasionally
// slips, especially when sourcing patterns the user already does.
const scrubAudit = [];
const enriched = themes.map(t => {
  const rawExamples = Array.isArray(t.example_posts) ? t.example_posts : [];
  const sampleComps = rawExamples.slice(0, 3).map(ex => String(ex.competitor || '(missing)'));
  const cleanExamples = rawExamples.filter(ex => {
    const comp = String(ex.competitor || '').replace(/^@/, '').toLowerCase();
    const isOwn = comp === 'own_account' || comp === 'user' || (own_username && comp === own_username);
    if (isOwn) console.log('Scrubbed own-handle example from theme "' + t.theme_name + '" (competitor="' + ex.competitor + '")');
    return !isOwn;
  });
  scrubAudit.push({
    name: t.theme_name || '(unnamed)',
    raw: rawExamples.length,
    final: cleanExamples.length,
    sample_competitors: sampleComps,
  });
  return Object.assign({}, t, { example_posts: cleanExamples });
});

// A theme with zero remaining examples after scrub had every example
// sourced from the user's own posts — invalid per the prompt and
// uninteresting to surface. Drop it.
const validThemes = enriched.filter(t => Array.isArray(t.example_posts) && t.example_posts.length > 0);
console.log('After own-scrub: ' + validThemes.length + ' of ' + themes.length + ' themes retained');

const final = validThemes.map(t => {
  const brief = (t.brief && typeof t.brief === 'object') ? t.brief : {};

  // performance_multiplier for display = avg outlier_ratio across the
  // example posts. avg_score (from Claude) is a different scale (uses
  // log10 of likes) and is harder to interpret as "Nx baseline" in the UI.
  const exampleRatios = (t.example_posts || [])
    .map(ex => Number(ex.outlier_ratio))
    .filter(n => Number.isFinite(n) && n > 0);
  const avgRatio = exampleRatios.length > 0
    ? exampleRatios.reduce((a, b) => a + b, 0) / exampleRatios.length
    : 0;
  const fallbackFromScore = typeof t.avg_score === 'number' ? t.avg_score : 0;
  const multiplier = avgRatio > 0
    ? Math.round(avgRatio * 10) / 10
    : (fallbackFromScore > 0 ? Math.round(fallbackFromScore * 10) / 10 : 1);

  // competitor_count = how many distinct creators contributed to this
  // theme's examples. Replaces the validated/standout dichotomy with a
  // simple "appears in N competitor accounts" signal.
  const distinctCompetitors = new Set();
  for (const ex of (t.example_posts || [])) {
    const c = String(ex.competitor || '').replace(/^@/, '').toLowerCase();
    if (c) distinctCompetitors.add(c);
  }

  const hashtags = Array.isArray(brief.hashtags)
    ? brief.hashtags.map(h => String(h).replace(/^#/, '').trim()).filter(Boolean)
    : null;

  const userDoes = t.user_already_does === true;
  const levelUp = userDoes && typeof t.level_up === 'string' && t.level_up.trim().length > 0
    ? t.level_up.slice(0, 500)
    : null;

  return {
    profile_id: own_profile_id,
    trend_name: t.theme_name || 'Unknown Theme',
    one_line_summary: typeof t.why_it_works === 'string' ? t.why_it_works.slice(0, 200) : null,
    // trend_type column is legacy (validated/standout). The redesign
    // collapses both into a single "theme" concept; storing null lets
    // pre-redesign rows still render with their old labels.
    trend_type: null,
    competitor_count: distinctCompetitors.size,
    total_competitors,
    confidence: distinctCompetitors.size / Math.max(total_competitors, 1),
    performance_multiplier: multiplier,
    why_it_works: typeof t.why_it_works === 'string' ? t.why_it_works : '',
    competitor_edge: levelUp,
    example_posts: JSON.stringify(t.example_posts || []),
    content_format: typeof brief.content === 'string' ? brief.content : null,
    hook: typeof brief.hook === 'string' ? brief.hook : null,
    caption_structure: typeof brief.caption === 'string' ? brief.caption : null,
    best_time: typeof brief.posting_time === 'string' ? brief.posting_time : null,
    hashtags: hashtags ? JSON.stringify(hashtags) : null,
    recommendation: typeof t.why_it_works === 'string' ? t.why_it_works : '',
    suggested_schedule: typeof brief.posting_time === 'string' ? brief.posting_time : '',
    is_mega_tip: !userDoes,
    user_doing_it: userDoes,
  };
});

const newOpps = final.filter(t => !t.user_doing_it).length;
const levelUps = final.filter(t => t.user_doing_it).length;
console.log('Inserting ' + final.length + ' themes — ' + newOpps + ' new opportunities, ' + levelUps + ' level-ups');

let stage = 'success';
if (themes.length === 0) stage = 'claude_returned_zero';
else if (validThemes.length === 0) stage = 'all_examples_scrubbed';

const metaItem = {
  json: {
    _empty: true,
    _meta: true,
    profile_id: own_profile_id,
    total_competitors,
    diag: {
      stage,
      claude_returned: themes.length,
      retained_after_scrub: validThemes.length,
      final: final.length,
      own_username,
      scrub_audit: scrubAudit,
    },
  },
};

if (final.length === 0) {
  return [metaItem];
}

return [...final.map(r => ({ json: r })), metaItem];

// Filter out the _empty sentinels that If-Has-Trends routes around the
// Insert step. There are two kinds: the legacy empty-run sentinel and
// the new _meta sentinel that always carries the diag payload (so we
// can audit partial-success runs too, not only full failures).
const allUpstream = $('Parse & Enrich Response').all();
const meta = allUpstream.find(i => i.json && i.json._meta);
const upstream = allUpstream.filter(i => !(i.json && i.json._empty));

const megaTips = upstream.filter(i => i.json.is_mega_tip).length;
const total = upstream.length;

// diag is now emitted on every run via the _meta sentinel from Parse &
// Enrich, so the frontend always knows where trends were lost.
const diag = meta ? meta.json.diag : null;

return [{
  json: {
    success: true,
    trends_detected: total,
    mega_tips: megaTips,
    insights: upstream.map(i => ({
      trend_name: i.json.trend_name,
      confidence_label: i.json.confidence_label,
      performance_multiplier: i.json.performance_multiplier,
      is_mega_tip: i.json.is_mega_tip,
      user_doing_it: i.json.user_doing_it
    })),
    ...(diag ? { diag } : {})
  }
}];
